// Simple 3x3 convolution kernel application
void applyKernel(int image[ROWS][COLS], int output[ROWS][COLS], 
                int kernel[3][3]) {
    for (int i = 1; i < ROWS - 1; i++) {
        for (int j = 1; j < COLS - 1; j++) {
            int sum = 0;
            // Multiply corresponding pixels and sum
            for (int ki = -1; ki <= 1; ki++) {
                for (int kj = -1; kj <= 1; kj++) {
                    sum += image[i + ki][j + kj] * kernel[ki + 1][kj + 1];
                }
            }
            output[i][j] = sum;
        }
    }
}

